using System.Collections;
using UnityEngine;

/// <summary>
/// Movimento aquático (Tarefa #14 — prioridade crítica): módulo referenciado
/// por PlayerMotor2D ("formas SwimOnly seriam movidas por um futuro
/// WaterMotor2D") que cobre:
///
/// - Natação horizontal/vertical, entrada/saída da água, superfície, mergulho
///   e flutuação (formas "Surface" não mergulham e voltam à superfície).
/// - Mudança de gravidade/resistência (drag) ao entrar/saír de água.
/// - Correntes (<see cref="AddCurrentForce"/>, usado por WaterCurrentZone).
/// - Impulso aquático (kick) ao premir Saltar dentro de água.
/// - Investida aquática da Orca (<see cref="StartAquaticCharge"/>, chamada
///   pelo ChargeAbility) — usa motor.SetDashing(true), o que faz
///   PlayerAttack.damageWhileDashing aplicar o dano de investida sem código
///   adicional.
/// - Aderência do Polvo (<see cref="canClingUnderwater"/> da forma): segurar
///   Interagir junto a uma superfície agarra o player (imóvel, sem
///   gravidade/correntes).
/// - Defesa da Tartaruga: respeita motor.MovementLocked (ShellGuardAbility já
///   trava o movimento — este módulo só precisa de não interferir).
/// - Câmara aquática/animações/VFX/áudio: triggers/bools no Animator
///   ("WaterEnter"/"WaterExit"/"AquaticImpulse"/"AquaticCharge"/"IsClinging")
///   + hooks de ParticleSystem/AudioClip.
///
/// PlayerMotor2D cede o controlo a este módulo enquanto <see cref="IsActive"/>
/// for true (forma aquática — SwimOnly ou swimType != None — e dentro de
/// água).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D), typeof(WaterDetector))]
public class WaterMotor2D : MonoBehaviour, IFormAbility
{
    [Header("Input")]
    [Tooltip("Auto-preenchido.")]
    [SerializeField] private PlayerInputRouter input;

    [Header("Aderência (Polvo — canClingUnderwater)")]
    [Tooltip("Layers consideradas 'superfície agarrável' debaixo de água (paredes/recifes/corais). Vazio = aderência nunca activa.")]
    [SerializeField] private LayerMask wallLayer;

    [Tooltip("Offset (a partir do transform do player) do centro da verificação de superfície agarrável.")]
    [SerializeField] private Vector2 clingCheckOffset = Vector2.zero;

    [Tooltip("Raio da verificação de superfície agarrável.")]
    [SerializeField] private float clingCheckRadius = 0.6f;

    [Header("VFX / Áudio — Entrada/Saída de Água")]
    [SerializeField] private ParticleSystem splashVfx;
    [SerializeField] private AudioClip enterWaterSfx;
    [SerializeField] private AudioClip exitWaterSfx;

    [Header("VFX / Áudio — Impulso Aquático")]
    [SerializeField] private ParticleSystem impulseVfx;
    [SerializeField] private AudioClip impulseSfx;

    [Header("VFX / Áudio — Investida Aquática (Orca)")]
    [SerializeField] private ParticleSystem chargeVfx;
    [SerializeField] private AudioClip chargeSfx;

    private PlayerMotor2D motor;
    private Rigidbody2D rb;
    private WaterDetector waterDetector;

    private AnimalFormData form;
    private bool enabledForForm;

    private float normalGravityScale;
    private float normalDrag;
    private bool wasInWater;

    private bool isClinging;
    private float impulseTimer;

    private bool isCharging;
    private Coroutine chargeRoutine;

    private Vector2 pendingCurrentForce;

    // Afogamento (swimType == None && floatsOnWaterSurface == false)
    private float sinkingTimer = -1f;           // -1 = não está a afogar
    private bool shownWaterWarningThisForm;     // aviso de tutorial mostrado nesta sessão de forma

    /// <summary>
    /// true enquanto a forma actual é aquática (SwimOnly ou swimType != None)
    /// E o player está dentro de água — PlayerMotor2D cede o controlo de
    /// movimento a este módulo enquanto isto for true.
    /// </summary>
    public bool IsActive => enabledForForm && waterDetector != null && waterDetector.IsInWater;

    /// <summary>
    /// true quando a forma é terrestre (swimType == None) mas tem
    /// <see cref="AnimalFormData.floatsOnWaterSurface"/> = true e o player
    /// está dentro de água. Neste estado o WaterMotor2D aplica gravidade
    /// reduzida + força de subida sem assumir controlo total do movimento
    /// (PlayerMotor2D continua a tratar o movimento horizontal).
    /// </summary>
    public bool IsFloating => !enabledForForm && form != null && form.floatsOnWaterSurface
        && waterDetector != null && waterDetector.IsInWater;

    /// <summary>
    /// true quando a forma não sabe nadar NEM flutua (swimType == None &&
    /// floatsOnWaterSurface == false) — entra em água → afunda e morre.
    /// </summary>
    private bool IsSinker => !enabledForForm && form != null
        && !form.floatsOnWaterSurface && form.swimType == SwimType.None;

    /// <summary>true enquanto o Polvo está agarrado a uma superfície (aderência).</summary>
    public bool IsClinging => isClinging;

    /// <summary>true durante a investida aquática da Orca.</summary>
    public bool IsCharging => isCharging;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
        waterDetector = GetComponent<WaterDetector>();

        if (input == null) input = GetComponentInParent<PlayerInputRouter>();

        normalDrag = rb.drag;
        normalGravityScale = rb.gravityScale;
    }

    private void OnEnable()
    {
        if (input != null) input.JumpPressed += OnJumpPressed;
    }

    private void OnDisable()
    {
        if (input != null) input.JumpPressed -= OnJumpPressed;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        EndAquaticCharge();
        StopCling();

        form = newForm;
        enabledForForm = form != null &&
            (form.movementMode == MovementMode.SwimOnly || form.swimType != SwimType.None);

        // Troca de forma cancela afogamento e reinicia aviso de tutorial.
        sinkingTimer = -1f;
        shownWaterWarningThisForm = false;

        normalGravityScale = form != null && form.gravityScale > 0f ? form.gravityScale : rb.gravityScale;

        bool inWater = waterDetector != null && waterDetector.IsInWater;

        if (enabledForForm && inWater)
        {
            rb.gravityScale = form.underwaterGravityScale;
            rb.drag = form.waterDrag;
        }
        else if (!enabledForForm && form != null && form.floatsOnWaterSurface && inWater)
        {
            rb.gravityScale = form.nonSwimmerWaterGravityScale;
            rb.drag = form.waterDrag;
        }
        else
        {
            rb.gravityScale = normalGravityScale;
            rb.drag = normalDrag;
        }

        wasInWater = inWater;
    }

    private void Update()
    {
        if (impulseTimer > 0f)
            impulseTimer -= Time.deltaTime;

        // Monitorizar mudanças de estado de água: formas aquáticas, flutuadores e
        // afundadores precisam todos de ser acompanhados.
        if (form == null || waterDetector == null) return;
        if (!enabledForForm && !form.floatsOnWaterSurface && !IsSinker) return;

        bool inWater = waterDetector.IsInWater;
        if (inWater != wasInWater)
        {
            OnWaterStateChanged(inWater);
            wasInWater = inWater;
        }

        // Contador de afogamento: tick quando submerso como "afundador".
        if (IsSinker && sinkingTimer >= 0f)
        {
            sinkingTimer -= Time.deltaTime;
            if (sinkingTimer <= 0f)
            {
                sinkingTimer = -1f;
                KillByDrowning();
            }
        }
    }

    private void OnWaterStateChanged(bool enteringWater)
    {
        if (enteringWater)
        {
            if (!motor.MovementLocked)
            {
                if (enabledForForm)
                {
                    // Forma aquática: usa gravidade/drag da natação.
                    rb.gravityScale = form.underwaterGravityScale;
                    rb.drag = form.waterDrag;
                }
                else if (form.floatsOnWaterSurface)
                {
                    // Animal terrestre flutuante: gravidade reduzida, drag leve.
                    rb.gravityScale = form.nonSwimmerWaterGravityScale;
                    rb.drag = form.waterDrag;
                }
                else if (IsSinker)
                {
                    // Afundador: afunda com a gravidade normal — apenas inicia o
                    // contador e mostra aviso de tutorial na primeira vez.
                    if (!string.IsNullOrEmpty(form.waterWarningText) && !shownWaterWarningThisForm)
                    {
                        shownWaterWarningThisForm = true;
                        TutorialMessageManager.Instance?.ShowMedia(form.waterWarningText);
                    }
                    sinkingTimer = form.sinkingDeathDelay;
                }
            }

            if (motor.Anim != null) motor.Anim.SetTrigger("WaterEnter");
            if (splashVfx != null) splashVfx.Play();
            AudioManager.Instance?.PlaySE(enterWaterSfx);
        }
        else
        {
            rb.gravityScale = normalGravityScale;
            rb.drag = normalDrag;

            // Saiu de água — cancela afogamento em curso.
            sinkingTimer = -1f;

            StopCling();
            EndAquaticCharge();

            if (motor.Anim != null) motor.Anim.SetTrigger("WaterExit");
            if (splashVfx != null) splashVfx.Play();
            AudioManager.Instance?.PlaySE(exitWaterSfx);
        }
    }

    private void FixedUpdate()
    {
        if (form == null) return;

        // Correntes (GDD: "correntes"/"correnteza segura até checkpoint"):
        // aplicam-se mesmo com o movimento bloqueado (ex.: ShellGuard) — a
        // corrente arrasta o jogador na mesma.
        if (pendingCurrentForce != Vector2.zero)
        {
            if (waterDetector.IsInWater)
                rb.velocity += pendingCurrentForce * Time.fixedDeltaTime;

            pendingCurrentForce = Vector2.zero;
        }

        // Investida aquática a decorrer: a coroutine controla a velocidade.
        if (isCharging) return;

        // Defesa da Tartaruga (ShellGuardAbility) e outros bloqueios de
        // movimento: não interferir.
        if (motor.MovementLocked)
        {
            if (isClinging) StopCling();
            return;
        }

        if (!IsActive)
        {
            if (isClinging) StopCling();

            // Não-nadador flutuante: aplica força de subida quando submerso.
            if (IsFloating) HandleNonSwimmerFloat();
            return;
        }

        HandleCling();
        if (isClinging)
        {
            rb.velocity = Vector2.zero;
            return;
        }

        HandleSwimMovement();
        HandleSurfaceCorrection();
    }

    // Flutuação de não-nadadores (swimType == None, floatsOnWaterSurface = true):
    // chamado no FixedUpdate quando IsFloating — aplica força de subida se
    // submerso, sem assumir o controlo horizontal (PlayerMotor2D continua activo).
    private void HandleNonSwimmerFloat()
    {
        if (form == null || form.nonSwimmerFloatSpeed <= 0f) return;
        if (!waterDetector.IsSubmerged) return;

        float vy = Mathf.MoveTowards(rb.velocity.y, form.nonSwimmerFloatSpeed,
            form.nonSwimmerFloatSpeed * 2f * Time.fixedDeltaTime);
        rb.velocity = new Vector2(rb.velocity.x, Mathf.Max(vy, rb.velocity.y));
    }

    // ---------------- Natação ----------------

    private void HandleSwimMovement()
    {
        Vector2 moveInput = input != null ? input.Move : Vector2.zero;

        float targetX = moveInput.x * form.swimSpeed;
        float targetY = moveInput.y * form.swimSpeed * form.verticalSwimMultiplier;

        // Formas de Superfície não mergulham activamente (sem descida por input).
        if (form.swimType == SwimType.Surface && targetY < 0f)
            targetY = 0f;

        bool hasInput = Mathf.Abs(moveInput.x) > 0.01f || Mathf.Abs(moveInput.y) > 0.01f;
        float accel = hasInput ? form.swimAccel : form.swimDecel;

        float newVX = Mathf.MoveTowards(rb.velocity.x, targetX, accel * Time.fixedDeltaTime);
        float newVY = Mathf.MoveTowards(rb.velocity.y, targetY, accel * Time.fixedDeltaTime);

        rb.velocity = new Vector2(newVX, newVY);
    }

    private void HandleSurfaceCorrection()
    {
        // Formas de Superfície arrastadas para debaixo de água (ex.: corrente)
        // sobem de volta à superfície sozinhas.
        if (form.swimType == SwimType.Surface && waterDetector.IsSubmerged && form.surfaceFloatSpeed > 0f)
        {
            float vy = Mathf.MoveTowards(rb.velocity.y, form.surfaceFloatSpeed, form.swimAccel * Time.fixedDeltaTime);
            rb.velocity = new Vector2(rb.velocity.x, Mathf.Max(vy, rb.velocity.y));
        }
    }

    // ---------------- Impulso Aquático ----------------

    private void OnJumpPressed()
    {
        if (!IsActive) return;
        if (motor.MovementLocked || isClinging || isCharging) return;
        if (impulseTimer > 0f) return;

        impulseTimer = form.aquaticImpulseCooldown;

        Vector2 moveInput = input != null ? input.Move : Vector2.zero;
        Vector2 dir = moveInput.sqrMagnitude > 0.01f
            ? moveInput.normalized
            : new Vector2(motor.FacingSign, 0.4f).normalized;

        rb.velocity += dir * form.aquaticImpulseForce;

        if (motor.Anim != null) motor.Anim.SetTrigger("AquaticImpulse");
        if (impulseVfx != null) impulseVfx.Play();
        AudioManager.Instance?.PlaySE(impulseSfx);
    }

    // ---------------- Aderência (Polvo) ----------------

    private void HandleCling()
    {
        if (form == null || !form.canClingUnderwater || input == null) return;

        bool touchingWall = wallLayer.value != 0 &&
            Physics2D.OverlapCircle((Vector2)transform.position + clingCheckOffset, clingCheckRadius, wallLayer);

        if (!isClinging && input.InteractHeld && touchingWall)
            StartCling();
        else if (isClinging && (!input.InteractHeld || !touchingWall))
            StopCling();
    }

    private void StartCling()
    {
        isClinging = true;
        rb.velocity = Vector2.zero;
        rb.gravityScale = 0f;

        if (motor.Anim != null) motor.Anim.SetBool("IsClinging", true);
    }

    private void StopCling()
    {
        if (!isClinging) return;

        isClinging = false;
        rb.gravityScale = IsActive ? form.underwaterGravityScale : normalGravityScale;

        if (motor.Anim != null) motor.Anim.SetBool("IsClinging", false);
    }

    // ---------------- Investida Aquática (Orca) ----------------

    /// <summary>
    /// Inicia a "investida aquática" da Orca (chamado pelo ChargeAbility
    /// quando IsActive). Move o player em linha recta a 'chargeSpeed' durante
    /// 'duration' segundos, marcando motor.SetDashing(true) — isto faz
    /// PlayerAttack.damageWhileDashing aplicar dano de contacto aos inimigos
    /// atingidos, sem código adicional aqui.
    /// </summary>
    public void StartAquaticCharge(float chargeSpeed, float duration)
    {
        if (!IsActive || isCharging) return;

        chargeRoutine = StartCoroutine(AquaticChargeRoutine(chargeSpeed, duration));
    }

    private IEnumerator AquaticChargeRoutine(float chargeSpeed, float duration)
    {
        isCharging = true;
        StopCling();
        motor.SetDashing(true);

        if (motor.Anim != null) motor.Anim.SetTrigger("AquaticCharge");
        if (chargeVfx != null) chargeVfx.Play();
        AudioManager.Instance?.PlaySE(chargeSfx);

        Vector2 moveInput = input != null ? input.Move : Vector2.zero;
        Vector2 dir = moveInput.sqrMagnitude > 0.01f
            ? moveInput.normalized
            : new Vector2(motor.FacingSign, 0f);

        float t = 0f;
        while (t < duration)
        {
            rb.velocity = dir * chargeSpeed;
            t += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        isCharging = false;
        chargeRoutine = null;
        motor.SetDashing(false);
    }

    /// <summary>
    /// Cancela a investida em curso (ex.: o player saiu de água, mudou de
    /// forma, ou morreu — chamado por ChargeAbility.Cancel via
    /// AbilityRouter.CancelAll(AbilityCancelReason.Death)). Pára a coroutine,
    /// repõe isCharging e motor.SetDashing(false) — sem isto, a velocidade da
    /// investida aquática continuaria a ser aplicada durante a morte.
    /// </summary>
    public void EndAquaticCharge()
    {
        if (!isCharging) return;

        if (chargeRoutine != null)
        {
            StopCoroutine(chargeRoutine);
            chargeRoutine = null;
        }

        isCharging = false;
        motor.SetDashing(false);
    }

    // ---------------- Correntes ----------------

    /// <summary>
    /// Chamado por WaterCurrentZone (OnTriggerStay2D) enquanto o player está
    /// dentro de uma zona de corrente: acumula uma força a aplicar no próximo
    /// FixedUpdate (independentemente de IsActive — a corrente arrasta o
    /// player mesmo que o movimento esteja bloqueado, ex.: ShellGuard).
    /// </summary>
    public void AddCurrentForce(Vector2 force)
    {
        // Bolha de Coral (Tarefa "Itens Consumíveis"): imunidade temporária a
        // correntes — ignora a força enquanto activa.
        if (PlayerConsumableEffects.Instance != null && PlayerConsumableEffects.Instance.IsCurrentImmune)
            return;

        // Tartaruga (Tarefa #7): resistência própria a correntes — reduz a
        // força recebida proporcionalmente a form.currentResistance (0-1).
        float resistance = form != null ? Mathf.Clamp01(form.currentResistance) : 0f;
        pendingCurrentForce += force * (1f - resistance);
    }

    // ---------------- Afogamento ----------------

    /// <summary>
    /// Chamado quando o contador de afogamento chega a zero — mata o player,
    /// que é respawnado no último checkpoint pelo sistema de saúde/respawn.
    /// </summary>
    private void KillByDrowning()
    {
        // Dano letal (instakill): mesmo padrão do OxygenSystem.Drown().
        var progress = PlayerProgress.Instance;
        if (progress != null)
            progress.Damage(progress.maxHearts + 1);
        else
            Debug.LogWarning("[WaterMotor2D] KillByDrowning: PlayerProgress.Instance não encontrado.");
    }

    private void OnDrawGizmosSelected()
    {
        if (wallLayer.value == 0) return;

        Gizmos.color = new Color(0.4f, 0.8f, 1f, 0.5f);
        Gizmos.DrawWireSphere((Vector2)transform.position + clingCheckOffset, clingCheckRadius);
    }
}
